UPDATE product_category
parent_id = #{parentId}, category_name = #{categoryName}, category_code = #{categoryCode}, level_no = #{levelNo}, sort_no = #{sortNo}, status = #{status}, remark = #{remark}, updated_by = #{updatedBy}
